10	//
11	// Authors:
12	// - Wolfgang Roenninger <wroennin@iis.ee.ethz.ch>
13	// - Andreas Kurth <akurth@iis.ee.ethz.ch>
14	
15	// Directed Random Verification Testbench for `axi_lite_regs`.
16	
17	`include "axi/assign.svh"
18	
19	/// Testbench for validating the module `axi_lite_regs`.
20	module tb_axi_lite_regs #(
21	  /// Define the parameter `RegNumBytes` of the DUT.
22	  parameter int unsigned              TbRegNumBytes  = 32'd200,
23	  /// Define the parameter `AxiReadOnly` of the DUT.
24	  parameter logic [TbRegNumBytes-1:0] TbAxiReadOnly  = {{TbRegNumBytes-18{1'b0}}, 18'b101110111111000000},
25	  /// Define the parameter `PrivProtOnly` of the DUT.
26	  parameter bit                       TbPrivProtOnly = 1'b0,
27	  /// Define the parameter `SecuProtOnly` of the DUT.
28	  parameter bit                       TbSecuProtOnly = 1'b0,
29	  /// Number of random writes generated by the testbench AXI4-Lite random master.
30	  parameter int unsigned              TbNoWrites     = 32'd1000,
31	  /// Number of random reads generated by the testbench AXI4-Lite random master.
32	  parameter int unsigned              TbNoReads      = 32'd1500
33	);
34	  // AXI configuration
35	  localparam int unsigned AxiAddrWidth = 32'd32;    // Axi Address Width
36	  localparam int unsigned AxiDataWidth = 32'd32;    // Axi Data Width
37	  localparam int unsigned AxiStrbWidth = AxiDataWidth / 32'd8;
38	  // timing parameters
39	  localparam time CyclTime = 10ns;
40	  localparam time ApplTime =  2ns;
41	  localparam time TestTime =  8ns;
42	
43	  typedef logic [7:0]              byte_t;
44	  typedef logic [AxiAddrWidth-1:0] axi_addr_t;
45	  typedef logic [AxiDataWidth-1:0] axi_data_t;
46	  typedef logic [AxiStrbWidth-1:0] axi_strb_t;
47	
48	  localparam axi_addr_t StartAddr = axi_addr_t'(0);
49	  localparam axi_addr_t EndAddr   =
50	      axi_addr_t'(StartAddr + TbRegNumBytes + TbRegNumBytes/5);
51	
52	  localparam byte_t [TbRegNumBytes-1:0] RegRstVal = '0;
53	
54	  typedef axi_test::axi_lite_rand_master #(
55	    // AXI interface parameters
56	    .AW ( AxiAddrWidth ),
57	    .DW ( AxiDataWidth ),
58	    // Stimuli application and test time
59	    .TA ( ApplTime  ),
60	    .TT ( TestTime  ),
61	    .MIN_ADDR ( StartAddr ),
62	    .MAX_ADDR ( EndAddr   ),
63	    .MAX_READ_TXNS  ( 10 ),
64	    .MAX_WRITE_TXNS ( 10 )
65	  ) rand_lite_master_t;
66	
67	  // -------------
68	  // DUT signals
69	  // -------------
70	  logic clk;
71	  // DUT signals
72	  logic rst_n;
73	  logic end_of_sim;
74	  // Register signals
75	  byte_t [TbRegNumBytes-1:0] reg_d,     reg_q;
76	  logic  [TbRegNumBytes-1:0] wr_active, rd_active, reg_load;
77	
78	  // -------------------------------
79	  // AXI Interfaces
80	  // -------------------------------
81	  AXI_LITE #(
82	    .AXI_ADDR_WIDTH ( AxiAddrWidth      ),
83	    .AXI_DATA_WIDTH ( AxiDataWidth      )
84	  ) master ();
85	  AXI_LITE_DV #(
86	    .AXI_ADDR_WIDTH ( AxiAddrWidth      ),
87	    .AXI_DATA_WIDTH ( AxiDataWidth      )
88	  ) master_dv (clk);
89	  `AXI_LITE_ASSIGN(master, master_dv)
90	
91	  // -------------------------------
92	  // AXI Rand Masters and Slaves
93	  // -------------------------------
94	  // Masters control simulation run time
95	  initial begin : proc_generate_axi_traffic
96	    automatic rand_lite_master_t lite_axi_master = new ( master_dv, "Lite Master");
97	    automatic axi_data_t      data = '0;
98	    automatic axi_pkg::resp_t resp = '0;
99	    end_of_sim <= 1'b0;
100	    lite_axi_master.reset();
101	    @(posedge rst_n);
102	    repeat (5) @(posedge clk);
103	    // Test known register.
104	    // Write to it.
105	    lite_axi_master.write(axi_addr_t'(32'h0000_0000), axi_pkg::prot_t'('0),
106	        axi_data_t'(64'hDEADBEEFDEADBEEF), axi_strb_t'(8'hFF), resp);
107	    if (TbPrivProtOnly || TbSecuProtOnly) begin
108	      assert (resp == axi_pkg::RESP_SLVERR) else
109	          $fatal(1, "PrivProtOnly || SecuProtOnly: Unprivileged access was falsely granted.");
110	    end else begin
111	      assert (resp == axi_pkg::RESP_OKAY) else
112	          $fatal(1, "Access should be granted");
113	    end
114	    // Read from it.
115	    lite_axi_master.read(axi_addr_t'(32'h0000_0000), axi_pkg::prot_t'('0), data, resp);
116	    if (TbPrivProtOnly || TbSecuProtOnly) begin
117	      // Expect error response
118	      assert (resp == axi_pkg::RESP_SLVERR) else
119	          $fatal(1, "PrivProtOnly || SecuProtOnly: Unprivileged access was falsely granted.");
120	      assert (data == axi_data_t'(32'hBA5E1E55)) else
121	          $fatal(1, "Data is unexpected, should be axi_data_t'(32'hBA5E1E55).");
122	    end else begin
123	      assert (resp == axi_pkg::RESP_OKAY) else
124	          $fatal(1, "Access should be granted.");
125	      // Checking of the expecetd read data is handled in `proc_check_read_data`.
126	    end
127	
128	    // Let random stimuli application checking is separate.
129	    lite_axi_master.run(TbNoReads, TbNoWrites);
130	    end_of_sim <= 1'b1;
131	  end
132	
133	  initial begin : proc_generate_direct_load
134	    for (int unsigned i = 0; i < TbRegNumBytes; i++) begin
135	      automatic int unsigned j = i;
136	      fork
137	        toggle_load(j);
138	      join_none
139	    end
140	  end
141	
142	  task automatic toggle_load(int unsigned byte_i);
143	    byte_t       rand_val;
144	    int unsigned rand_wait;
145	    @(posedge rst_n);
146	    reg_load[byte_i] = 1'b0;
147	    reg_d[byte_i]    = 8'h00;
148	    @(posedge clk);
149	    forever begin
150	      rand_wait = $urandom_range(0, 20);
151	      repeat (rand_wait) @(posedge clk);
152	      rand_val          = byte_t'($urandom());
153	      reg_d[byte_i]    <= #ApplTime rand_val;
154	      reg_load[byte_i] <= #ApplTime 1'b1;
155	      @(posedge clk);
156	      reg_d[byte_i]    <= #ApplTime '0;
157	      reg_load[byte_i] <= #ApplTime 1'b0;
158	    end
159	  endtask : toggle_load
160	
161	  initial begin : proc_check_read_data
162	    automatic axi_data_t      exp_rdata[$];
163	    automatic axi_pkg::resp_t exp_resp[$];
164	
165	    @(posedge rst_n);
166	    forever begin
167	      @(posedge clk);
168	      #(TestTime);
169	
170	      // Push the expected data back.
171	      if (master.ar_valid && master.ar_ready) begin
172	        automatic int unsigned ar_idx = ((master.ar_addr - StartAddr)
173	            >> $clog2(AxiStrbWidth) << $clog2(AxiStrbWidth));
174	        automatic axi_data_t      r_data = axi_data_t'(0);
175	        automatic axi_pkg::resp_t r_resp = axi_pkg::RESP_SLVERR;
176	        for (int unsigned i = 0; i < AxiStrbWidth; i++) begin
177	          if ((ar_idx+i) < TbRegNumBytes) begin
178	            r_data[8*i+:8] = reg_q[ar_idx+i];
179	            r_resp         = axi_pkg::RESP_OKAY;
180	          end else begin
181	            r_data[8*i+:8] = 8'hxx;
182	          end
183	        end
184	        // check the right protection access
185	        if (TbPrivProtOnly && !master.ar_prot[0]) begin
186	          r_resp = axi_pkg::RESP_SLVERR;
187	        end
188	        if (TbSecuProtOnly && !master.ar_prot[1]) begin
189	          r_resp = axi_pkg::RESP_SLVERR;
190	        end
191	        exp_resp.push_back(r_resp);
192	        exp_rdata.push_back(r_data);
193	      end
194	
195	      // compare data if there is a value expected
196	      if (master.r_valid && master.r_ready) begin
197	        automatic axi_data_t r_data = exp_rdata.pop_front();
198	        if (master.r_resp == axi_pkg::RESP_OKAY) begin
199	          for (int unsigned i = 0; i < AxiStrbWidth; i++) begin
200	            automatic byte_t exp_byte = r_data[8*i+:8];
201	            if (exp_byte !== 8'hxx) begin
202	              assert (master.r_data[8*i+:8] == exp_byte) else
203	                  $error("Unexpected read data: exp: %0h observed: %0h", r_data, master.r_data);
204	              assert (master.r_resp == axi_pkg::RESP_OKAY);
205	            end
206	          end
207	        end else if (master.r_resp == axi_pkg::RESP_SLVERR) begin
208	          assert (master.r_data == axi_data_t'(32'hBA5E1E55));
209	        end else begin
210	          $error("Slave responded with false response: %0h", master.r_resp);
211	        end
212	      end
213	    end
214	  end
215	
216	  axi_pkg::resp_t b_resp_queue[$];
217	
218	  // Only works as module expects both AW & W valid before it does something
219	  initial begin : proc_check_write_data
220	    @(posedge rst_n);
221	    forever begin
222	      #TestTime;
223	      // AW and W is launched, setup the test tasks
224	      if (master.aw_valid && master.aw_ready && master.w_valid && master.w_ready) begin
225	        automatic int unsigned aw_idx = ((master.aw_addr - StartAddr)
226	            >> $clog2(AxiStrbWidth) << $clog2(AxiStrbWidth));
227	        automatic axi_pkg::resp_t exp_b_resp = (aw_idx < TbRegNumBytes) ?
228	            axi_pkg::RESP_OKAY : axi_pkg::RESP_SLVERR;
229	        automatic bit all_ro = 1'b1;
230	        // check for errors from wrong access protection
231	        if (TbPrivProtOnly && !master.aw_prot[0]) begin
232	          exp_b_resp = axi_pkg::RESP_SLVERR;
233	        end
234	        if (TbSecuProtOnly && !master.aw_prot[1]) begin
235	          exp_b_resp = axi_pkg::RESP_SLVERR;
236	        end
237	        // Check if all accesses bytes are read only
238	        for (int unsigned i = 0; i < AxiStrbWidth; i++) begin
239	          if (!TbAxiReadOnly[aw_idx+i]) begin
240	            all_ro = 1'b0;
241	          end
242	        end
243	        if (all_ro) begin
244	          exp_b_resp = axi_pkg::RESP_SLVERR;
245	        end
246	
247	        // do the actual write checking
248	        if (exp_b_resp == axi_pkg::RESP_OKAY) begin
249	          // go through every byte
250	          for (int unsigned i = 0; i < AxiStrbWidth; i++) begin
251	            if ((aw_idx+i) < TbRegNumBytes) begin
252	              if (master.w_strb[i]) begin
253	                automatic int unsigned        j = aw_idx + i;
254	                automatic byte_t       exp_byte = master.w_data[8*i+:8];
255	                fork
256	                  check_q(j, exp_byte);
257	                join_none
258	              end
259	              assert (master.w_strb[i] == wr_active[aw_idx+i]);
260	            end
261	          end
262	        end
263	        b_resp_queue.push_back(exp_b_resp);
264	      end
265	      @(posedge clk);
266	    end
267	  end
268	
269	  initial begin : proc_check_b
270	    automatic axi_pkg::resp_t exp_b_resp;
271	    @(posedge rst_n);
272	    forever begin
273	      #TestTime;
274	      if (master.b_valid && master.b_ready) begin
275	        if (b_resp_queue.size()) begin
276	          exp_b_resp = b_resp_queue.pop_front();
277	          assert (exp_b_resp == master.b_resp) else
278	              $error("Unexpected B response: EXP: %b ACT: %b", exp_b_resp, master.b_resp);
279	        end else begin
280	          $error("B response even no AW was sent.");
281	        end
282	      end
283	      @(posedge clk);
284	    end
285	  end
286	
287	  // check that the expected register byte has been written
288	  task automatic check_q(int unsigned byte_i, byte_t exp_byte);
289	    automatic byte_t save_byte = (reg_load[byte_i]) ? reg_d[byte_i] : reg_q[byte_i];
290	    @(posedge clk);
291	    #TestTime;
292	    if (!TbAxiReadOnly[byte_i]) begin
293	      assert(exp_byte == reg_q[byte_i]) else
294	          $error("AXI write was not registered at byte: %0d", byte_i);
295	    end else begin
296	      assert (reg_q[byte_i] == save_byte) else
297	          $error("AXI write onto read only byte: %0d SAVE: %h EXP: %h ACT %h",
298	              byte_i, save_byte, exp_byte, reg_q[byte_i]);
299	    end
300	  endtask : check_q
301	
302	  // Some assertions for additional checking.
303	  default disable iff (~rst_n);
304	  for (genvar i = 0; i < TbRegNumBytes; i++) begin : gen_check_ro_bytes
305	    if (TbAxiReadOnly[i]) begin : gen_check_ro
306	      ro_assert_no_load: assert property (@(posedge clk)
307	          ((wr_active[i] && !reg_load[i]) |=> $stable(reg_q[i]))) else
308	          $fatal(1, "ReadOnly byte %0d changed from AXI write, while not direct loaded.", i);
309	      ro_assert_load: assert property (@(posedge clk)
310	          ((wr_active[i] && reg_load[i]) |=> (reg_q[i] === $past(reg_d[i])))) else
311	          $fatal(1, "ReadOnly byte %0d changed from AXI write, while direct loaded.", i);
312	    end
313	    load_assert_no_axi: assert property (@(posedge clk)
314	        (reg_load[i] && !TbAxiReadOnly[i] |-> !wr_active[i])) else
315	        $fatal(1, "Byte %0d, AXI write onto non read-only and direct load are both active!", i);
316	    load_assert_data:   assert property (@(posedge clk)
317	        (reg_load[i] |=> reg_q[i] === $past(reg_d[i]))) else
318	        $fatal(1, "Byte %0d, direct load was executed falsely.", i);
319	    stable_assert:      assert property (@(posedge clk)
320	        (!reg_load[i] && !wr_active[i]) |=> $stable(reg_q[i])) else
321	        $fatal(1, "Byte %0d is unstable, when no AXI write or direct load.", i);
322	  end
323	
324	  initial begin : proc_stop_sim
325	    wait (end_of_sim);
326	    repeat (1000) @(posedge clk);
327	    $display("Simulation stopped as Master transferred its data.");
328	    $stop();
329	  end
330	
331	  //-----------------------------------
332	  // Clock generator
333	  //-----------------------------------
334	  clk_rst_gen #(
335	    .ClkPeriod    ( CyclTime ),
336	    .RstClkCycles ( 5        )
337	  ) i_clk_gen (
338	    .clk_o (clk),
339	    .rst_no(rst_n)
340	  );
341	
342	  //-----------------------------------
343	  // DUT
344	  //-----------------------------------
345	  axi_lite_regs_intf #(
346	    .REG_NUM_BYTES  ( TbRegNumBytes  ),
347	    .AXI_ADDR_WIDTH ( AxiAddrWidth   ),
348	    .AXI_DATA_WIDTH ( AxiDataWidth   ),
349	    .PRIV_PROT_ONLY ( TbPrivProtOnly ),
350	    .SECU_PROT_ONLY ( TbSecuProtOnly ),
351	    .AXI_READ_ONLY  ( TbAxiReadOnly  ),
352	    .REG_RST_VAL    ( RegRstVal      )
353	  ) i_axi_lite_regs (
354	    .clk_i       ( clk       ),
355	    .rst_ni      ( rst_n     ),
356	    .slv         ( master    ),
357	    .wr_active_o ( wr_active ),
358	    .rd_active_o ( rd_active ),
359	    .reg_d_i     ( reg_d     ),
360	    .reg_load_i  ( reg_load  ),
361	    .reg_q_o     ( reg_q     )
362	  );
363	endmodule
364

